import { useState } from "react";
import { Key } from "lucide-react";
import { Modal } from "./Modal";
import { OdsAlert } from "./OdsAlert";
import { OdsButton } from "./OdsButton";
import { useCreateOrderlyKey } from "@/hooks/useCreateOrderlyKey";
import { hasCompleteStoredAdminApiKey } from "@/utils/adminKeyAuth";
import { Trans, useTranslation } from "@/i18n";
import { toast } from "@/hooks/use-toast";

interface CreateOrderlyKeyModalProps {
  open: boolean;
  onClose: () => void;
  onSuccess?: () => void;
  brokerId: string;
  delegateContract?: string;
}

export function CreateOrderlyKeyModal({
  open,
  onClose,
  onSuccess,
  brokerId,
  delegateContract,
}: CreateOrderlyKeyModalProps) {
  const { create, loading, switching, error, clearError } =
    useCreateOrderlyKey();
  const { t } = useTranslation();
  const [localError, setLocalError] = useState("");
  const isMultisig = Boolean(delegateContract);
  const busy = loading || switching;

  async function handleCreate() {
    setLocalError("");
    clearError();
    if (!brokerId) {
      setLocalError(t("createApiKey.noBrokerId"));
      return;
    }

    try {
      await create({ brokerId, delegateContract });
      toast({ title: t("login.apiKeyCreated") });
      onSuccess?.();
      onClose();
    } catch (err) {
      console.error("CreateOrderlyKeyModal error:", err);
      setLocalError(
        err instanceof Error ? err.message : t("createApiKey.failed")
      );
    }
  }

  const displayError = error || localError;

  return (
    <Modal
      open={open}
      onClose={busy ? () => {} : onClose}
      title={t("login.createApiKey")}
    >
      <div className="space-y-5">
        <div className="mx-auto flex h-11 w-11 items-center justify-center rounded-xl bg-[var(--bg-primary-subtle)] text-[var(--fg-brand)]">
          <Key className="h-5 w-5" />
        </div>
        <p className="text-center text-sm leading-5 text-[var(--fg-secondary)]">
          {t("login.storeSecretSafely")}
        </p>

        {isMultisig && (
          <OdsAlert type="info">
            <Trans
              i18nKey="createApiKey.delegateNotice"
              values={{ address: delegateContract }}
              components={{
                address: <span className="font-mono text-[var(--fg-base)]" />,
              }}
            />
            {switching && (
              <span className="mt-1 block">
                {t("createApiKey.switchingHint")}
              </span>
            )}
          </OdsAlert>
        )}

        {displayError && <OdsAlert type="negative">{displayError}</OdsAlert>}

        <div className="flex flex-col-reverse gap-3 sm:flex-row sm:justify-end">
          <OdsButton
            type="button"
            variant="secondary"
            size="large"
            disabled={busy}
            onClick={onClose}
            className="w-full sm:w-auto"
          >
            {t("common.cancel")}
          </OdsButton>
          <OdsButton
            type="button"
            variant="primary"
            size="large"
            disabled={busy}
            onClick={() => void handleCreate()}
            className="w-full gap-2 sm:w-auto"
          >
            {busy && (
              <span className="inline-block h-4 w-4 animate-spin rounded-full border-2 border-[var(--line-strong)] border-t-[var(--fg-base)]" />
            )}
            {switching
              ? t("createApiKey.switchingNetwork")
              : loading
                ? t("createApiKey.creating")
                : t("login.createApiKey")}
          </OdsButton>
        </div>
      </div>
    </Modal>
  );
}

export function useRequireOrderlyKeyModal(
  brokerId?: string | null,
  delegateContract?: string
) {
  const [open, setOpen] = useState(false);
  const hasCompleteKey =
    typeof window !== "undefined" ? hasCompleteStoredAdminApiKey() : false;

  function requestKey() {
    setOpen(true);
  }

  function handleClose() {
    setOpen(false);
  }

  const modal = brokerId ? (
    <CreateOrderlyKeyModal
      open={open}
      onClose={handleClose}
      onSuccess={handleClose}
      brokerId={brokerId}
      delegateContract={delegateContract}
    />
  ) : null;

  return { modal, requestKey, hasKey: hasCompleteKey };
}
