import { useEffect, useRef, useState } from "react";
import { LocalizedLink, useLocalizedNavigate } from "@/utils/localizedRoute";
import { ChevronDown, Menu } from "lucide-react";
import { useAccount, useConnections, useDisconnect } from "wagmi";
import { NetworkSelector } from "./NetworkSelector";
import { disconnectWalletCompletely } from "@/utils/session";
import { fetchDexCreatorDexStatus } from "@/services/orderly";
import { useTranslation } from "@/i18n";
import { getProfile } from "@/utils/branding-shared";
import { walletGetItem, walletSetItem } from "@/utils/storage";
import { toggleSidebarMobile } from "./Sidebar";

function abbreviate(str: string, start = 6, end = 4): string {
  if (!str || str.length <= start + end + 3) return str;
  return str.slice(0, start) + "..." + str.slice(-end);
}

function getLoginContext() {
  if (typeof window === "undefined") return null;
  const raw = walletGetItem("orderlyLoginContext");
  if (!raw) return null;
  try {
    return JSON.parse(raw) as {
      method?: "wallet" | "api";
      walletAddress?: string;
      accountId?: string;
    };
  } catch {
    return null;
  }
}

export function AppHeader({
  pageTitle,
  parentTitle,
}: {
  pageTitle: string;
  parentTitle?: string;
}) {
  const navigate = useLocalizedNavigate();
  const { t } = useTranslation();
  const { address } = useAccount();
  const connections = useConnections();
  const { disconnectAsync } = useDisconnect();
  const [open, setOpen] = useState(false);
  const [profile, setProfile] = useState<ReturnType<typeof getProfile>>(null);
  const [context, setContext] =
    useState<ReturnType<typeof getLoginContext>>(null);
  const menuRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    setProfile(getProfile());
    setContext(getLoginContext());
  }, []);

  useEffect(() => {
    function refreshSession() {
      setProfile(getProfile());
      setContext(getLoginContext());
    }

    window.addEventListener("authChanged", refreshSession);
    window.addEventListener("profileUpdated", refreshSession);
    window.addEventListener("storage", refreshSession);
    return () => {
      window.removeEventListener("authChanged", refreshSession);
      window.removeEventListener("profileUpdated", refreshSession);
      window.removeEventListener("storage", refreshSession);
    };
  }, []);

  useEffect(() => {
    if (profile?.role === "ambassador" || profile?.brokerId === "ambassador")
      return;
    if (profile?.logo) return;

    let cancelled = false;
    fetchDexCreatorDexStatus()
      .then(status => {
        if (cancelled || !status || status.exists === false) return;
        const logo =
          status.logo || status.primaryLogo || status.secondaryLogo || null;
        if (!logo) return;
        setProfile(current => {
          const next = {
            ...(current || getProfile() || {}),
            primaryLogo: status.primaryLogo || null,
            secondaryLogo: status.secondaryLogo || null,
            logo,
          };
          if (typeof window !== "undefined")
            walletSetItem("orderlyProfile", JSON.stringify(next));
          return next;
        });
      })
      .catch(() => {
        // Header falls back to initials when DEX status is unavailable.
      });

    return () => {
      cancelled = true;
    };
  }, [
    profile?.role,
    profile?.brokerId,
    profile?.primaryLogo,
    profile?.secondaryLogo,
    profile?.logo,
  ]);

  useEffect(() => {
    function handleClickOutside(e: MouseEvent) {
      if (menuRef.current && !menuRef.current.contains(e.target as Node)) {
        setOpen(false);
      }
    }
    document.addEventListener("click", handleClickOutside);
    return () => document.removeEventListener("click", handleClickOutside);
  }, []);

  const displayName = profile?.builderName || "Builder";
  const initials = displayName.slice(0, 2).toUpperCase();
  const builderLogo =
    profile?.logo || profile?.primaryLogo || profile?.secondaryLogo || null;

  let walletText = "";
  if (address) {
    walletText = abbreviate(address, 6, 4);
  } else if (context?.method === "wallet" && context.walletAddress) {
    walletText = abbreviate(context.walletAddress, 6, 4);
  } else if (context?.method === "api" && context.accountId) {
    walletText = abbreviate(context.accountId, 6, 4);
  }

  async function handleLogout() {
    if (typeof window === "undefined") return;
    await disconnectWalletCompletely(disconnectAsync, connections);
    setProfile(null);
    setContext(null);
    setOpen(false);
    navigate("/login");
  }

  const isAmbassadorDistributor =
    profile?.role === "ambassador" || profile?.brokerId === "ambassador";

  return (
    <header
      className="sticky top-0 z-40 border-b border-[var(--border-subtle)] bg-bg-base/80 backdrop-blur-[12px]"
      aria-label="App header"
    >
      <div className="mx-auto flex h-16 max-w-350 items-center justify-between px-4 md:px-8">
        <h1 className="text-2xl font-display font-medium text-[var(--fg-base)]">
          {parentTitle || pageTitle}
        </h1>

        <div className="flex items-center gap-2 md:gap-3">
          <button
            type="button"
            aria-label="Open navigation menu"
            onClick={() => {
              toggleSidebarMobile();
              window.dispatchEvent(
                new CustomEvent("sidebarMobileToggle", {
                  detail: { open: true },
                })
              );
            }}
            className="inline-flex h-10 w-10 items-center justify-center rounded-xl border border-line-subtle text-fg-base transition-colors hover:bg-bg-hover md:hidden"
          >
            <Menu className="h-5 w-5" />
          </button>

          <div className="hidden md:block">
            <NetworkSelector />
          </div>

          <div className="relative" ref={menuRef}>
            <button
              type="button"
              onClick={() => setOpen(v => !v)}
              aria-haspopup="true"
              aria-expanded={open}
              className="flex h-10 items-center gap-2.5 rounded-[24px] bg-[var(--bg-secondary)] px-3 text-[var(--fg-base)] transition-opacity hover:opacity-90"
            >
              {builderLogo ? (
                <img
                  src={builderLogo}
                  alt=""
                  className="h-7 w-7 shrink-0 rounded-full object-contain"
                />
              ) : (
                <div className="grid h-7 w-7 shrink-0 place-items-center rounded-full bg-[var(--bg-primary)] text-sm font-semibold text-[var(--fg-base)]">
                  {initials}
                </div>
              )}
              <div className="text-left">
                <div className="text-sm font-medium text-[var(--fg-base)]">
                  {displayName}
                </div>
                <div className="text-xs text-fg-secondary">{walletText}</div>
              </div>
              <ChevronDown
                className={`h-3.5 w-3.5 text-fg-secondary transition-transform ${
                  open ? "rotate-180" : ""
                }`}
              />
            </button>

            {open && (
              <div className="absolute right-0 top-[calc(100%+8px)] z-50 flex min-w-[240px] flex-col gap-1.5 rounded-lg bg-[var(--bg-surface-primary)] p-4 shadow-popout animate-slide-up">
                {isAmbassadorDistributor ? (
                  <>
                    <LocalizedLink
                      to="/distributor-dashboard"
                      className="flex min-h-[51px] items-center rounded-lg px-3 py-2 text-sm font-medium text-[var(--fg-base)] transition-colors hover:bg-bg-hover"
                      onClick={() => setOpen(false)}
                    >
                      {t("navigation.distributorProgramSidebar")}
                    </LocalizedLink>
                    <LocalizedLink
                      to="/settings"
                      className="flex min-h-[51px] items-center rounded-lg px-3 py-2 text-sm font-medium text-[var(--fg-base)] transition-colors hover:bg-bg-hover"
                      onClick={() => setOpen(false)}
                    >
                      {t("navigation.settings")}
                    </LocalizedLink>
                  </>
                ) : (
                  <LocalizedLink
                    to="/home"
                    className="flex min-h-[51px] items-center rounded-lg px-3 py-2 text-sm font-medium text-[var(--fg-base)] transition-colors hover:bg-bg-hover"
                    onClick={() => setOpen(false)}
                  >
                    {t("navigation.myDex")}
                  </LocalizedLink>
                )}
                <button
                  type="button"
                  onClick={handleLogout}
                  className="flex min-h-[51px] items-center rounded-lg px-3 py-2 text-left text-sm font-medium text-[var(--fg-base)] transition-colors hover:bg-bg-hover"
                >
                  {t("common.logOut")}
                </button>
              </div>
            )}
          </div>
        </div>
      </div>
    </header>
  );
}
