import { useLocation } from "@remix-run/react";
import { LocalizedLink } from "@/utils/localizedRoute";
import React, { useCallback, useEffect, useState } from "react";
import {
  LayoutGrid,
  Store,
  Share2,
  Wallet,
  Users,
  List,
  TrendingUp,
  Landmark,
  Trophy,
  Settings,
  PanelLeft,
  Receipt,
  Settings2,
  Image,
  Tag,
  BarChart3,
  Database,
} from "lucide-react";
import { OrderlyOneMobileLogoLockup } from "./OrderlyOneLogoLockup";
import { OrderlyLogo } from "./OrderlyLogo";
import { PointsIcon } from "./PointsIcon";
import { useTranslation } from "@/i18n";
import { LanguageSwitcher } from "./LanguageSwitcher";
import { NetworkSelector } from "./NetworkSelector";
import { type Profile, getProfile } from "@/utils/branding-shared";
import { shouldRequireOrderlyApiKey } from "@/utils/adminKeyAuth";
import {
  getInitialSidebarCollapsed,
  getStoredSidebarCollapsed,
  saveSidebarCollapsed,
  shouldCollapseSidebarForViewport,
  SIDEBAR_COLLAPSE_MEDIA_QUERY,
} from "@/utils/sidebar";
import { walletGetItem } from "@/utils/storage";

type NavItem =
  | {
      type: "link";
      id: string;
      label: string;
      href: string;
      icon: React.ElementType;
      external?: boolean;
    }
  | { type: "header"; label: string }
  | { type: "divider" };

function getLoginMethod(): "wallet" | "api" | null {
  if (typeof window === "undefined") return null;
  const raw = walletGetItem("orderlyLoginContext");
  if (!raw) return null;
  try {
    const context = JSON.parse(raw) as { method?: "wallet" | "api" };
    return context.method || null;
  } catch {
    return null;
  }
}

let globalMobileOpen = false;
const mobileOpenListeners = new Set<(open: boolean) => void>();

export function setSidebarMobileOpen(open: boolean) {
  globalMobileOpen = open;
  mobileOpenListeners.forEach(fn => fn(open));
}

export function toggleSidebarMobile() {
  setSidebarMobileOpen(!globalMobileOpen);
}

export function Sidebar({
  mobileOpen,
  onMobileOpenChange,
}: {
  mobileOpen?: boolean;
  onMobileOpenChange?: (open: boolean) => void;
}) {
  const location = useLocation();
  const pathname = getRoutePathname(location.pathname);
  const { t } = useTranslation();
  const [collapsed, setCollapsed] = useState(false);
  const [profile, setProfile] = useState<Profile | null>(null);
  const [loginMethod, setLoginMethod] = useState<"wallet" | "api" | null>(null);
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
    if (typeof window === "undefined") return;
    setCollapsed(getInitialSidebarCollapsed());
    setProfile(getProfile());
    setLoginMethod(getLoginMethod());
  }, []);

  useEffect(() => {
    if (typeof window === "undefined") return;

    function handleProfileUpdate() {
      setProfile(getProfile());
      setLoginMethod(getLoginMethod());
    }

    function handleViewportChange() {
      if (getStoredSidebarCollapsed() !== null) return;
      const next = shouldCollapseSidebarForViewport();
      setCollapsed(next);
      window.dispatchEvent(
        new CustomEvent("sidebarToggle", { detail: { collapsed: next } })
      );
    }

    const viewportQuery = window.matchMedia(SIDEBAR_COLLAPSE_MEDIA_QUERY);
    viewportQuery.addEventListener("change", handleViewportChange);
    window.addEventListener("profileUpdated", handleProfileUpdate);
    return () => {
      viewportQuery.removeEventListener("change", handleViewportChange);
      window.removeEventListener("profileUpdated", handleProfileUpdate);
    };
  }, []);

  const closeMobile = useCallback(() => {
    onMobileOpenChange?.(false);
    setSidebarMobileOpen(false);
  }, [onMobileOpenChange]);

  useEffect(() => {
    if (!mobileOpen) return;
    if (pathname) closeMobile();
  }, [pathname]);

  function toggleSidebar() {
    const next = !collapsed;
    setCollapsed(next);
    if (typeof window !== "undefined") {
      saveSidebarCollapsed(next);
      window.dispatchEvent(
        new CustomEvent("sidebarToggle", { detail: { collapsed: next } })
      );
    }
  }

  const isAmbassadorDistributor =
    profile?.role === "ambassador" || profile?.brokerId === "ambassador";
  const isDistributorAccount =
    isAmbassadorDistributor || profile?.role === "broker";
  const canAccessDistributor = shouldRequireOrderlyApiKey(profile);
  const graduated = !!profile?.graduated;
  const isApiLogin = loginMethod === "api";

  const divider: NavItem = { type: "divider" };
  const distributorNavItem: NavItem = {
    type: "link",
    id: "distributor-dashboard",
    label: t("navigation.distributorProgramSidebar"),
    href: "/distributor-dashboard",
    icon: Share2,
  };
  const settingsNavItem: NavItem = {
    type: "link",
    id: "settings",
    label: t("navigation.settings"),
    href: "/settings",
    icon: Settings,
  };
  const orderlyEcosystemNavItems: NavItem[] = [
    { type: "header", label: t("navigation.orderlyEcosystem") },
    {
      type: "link",
      id: "staking",
      label: t("navigation.staking"),
      href: "https://app.orderly.network/staking",
      icon: TrendingUp,
      external: true,
    },
    {
      type: "link",
      id: "strategy-vault",
      label: t("navigation.strategyVaults"),
      href: "https://app.orderly.network/vaults",
      icon: Landmark,
      external: true,
    },
    {
      type: "link",
      id: "campaigns",
      label: t("navigation.campaigns"),
      href: "https://app.orderly.network/campaigns/",
      icon: Trophy,
      external: true,
    },
  ];
  const marketplaceNavItem: NavItem = {
    type: "link",
    id: "module-hub",
    label: t("navigation.moduleHub"),
    href: "https://marketplace.orderly.network/",
    icon: Store,
    external: true,
  };

  function withOrderlyEcosystemAndSettings(
    items: NavItem[],
    options: { includeMarketplace?: boolean } = { includeMarketplace: true }
  ): NavItem[] {
    const ecosystemItems = options.includeMarketplace
      ? [...orderlyEcosystemNavItems, marketplaceNavItem]
      : orderlyEcosystemNavItems;
    return [
      ...items,
      ...(items.length > 0 ? [divider] : []),
      ...ecosystemItems,
      divider,
      settingsNavItem,
    ];
  }

  const AMBASSADOR_NAV_ITEMS: NavItem[] = withOrderlyEcosystemAndSettings(
    [
      {
        type: "link",
        id: "distributor-dashboard",
        label: t("navigation.distributorProgramSidebar"),
        href: "/distributor-dashboard",
        icon: Share2,
      },
    ],
    { includeMarketplace: false }
  );

  const ALL_NAV_ITEMS: NavItem[] = withOrderlyEcosystemAndSettings(
    [
      {
        type: "link",
        id: "dashboard",
        label: t("navigation.myDex"),
        href: "/home",
        icon: LayoutGrid,
      },
      {
        type: "link",
        id: "finance",
        label: t("navigation.finance"),
        href: "/finance",
        icon: Wallet,
      },
      { type: "divider" },
      { type: "header", label: t("navigation.dexConfigurations") },
      {
        type: "link",
        id: "frontend-setup",
        label: t("navigation.frontendSetup"),
        href: "/frontend-setup",
        icon: Settings2,
      },
      {
        type: "link",
        id: "fee-settings",
        label: t("navigation.feeSettings"),
        href: "/fee-settings",
        icon: Receipt,
      },
      {
        type: "link",
        id: "order-tags",
        label: t("navigation.orderEnum"),
        href: "/order-tags",
        icon: Tag,
      },
      {
        type: "link",
        id: "dex-card",
        label: t("navigation.dexCard"),
        href: "/dex-card",
        icon: Image,
      },
      { type: "divider" },
      { type: "header", label: t("navigation.growth") },
      {
        type: "link",
        id: "affiliate",
        label: t("navigation.affiliateProgram"),
        href: "/affiliate",
        icon: Users,
      },
      {
        type: "link",
        id: "points",
        label: t("navigation.pointsSystem"),
        href: "/points",
        icon: PointsIcon,
      },
      ...(canAccessDistributor ? [distributorNavItem] : []),
      { type: "divider" },
      { type: "header", label: t("navigation.dataAnalytics") },
      {
        type: "link",
        id: "data-analytics",
        label: t("navigation.users"),
        href: "/data-analytics/users",
        icon: BarChart3,
      },
      {
        type: "link",
        id: "data-analytics-platform",
        label: t("navigation.platform"),
        href: "/data-analytics/platform",
        icon: Database,
      },
      { type: "divider" },
      { type: "header", label: t("navigation.listing") },
      {
        type: "link",
        id: "permissionless-listing",
        label: t("navigation.permissionlessListing"),
        href: "/permissionless-listing",
        icon: List,
      },
    ],
    { includeMarketplace: true }
  );

  const DISTRIBUTOR_NAV_ITEMS: NavItem[] = withOrderlyEcosystemAndSettings([
    {
      type: "link",
      id: "dashboard",
      label: t("navigation.myDex"),
      href: "/home",
      icon: LayoutGrid,
    },
    {
      type: "link",
      id: "finance",
      label: t("navigation.finance"),
      href: "/finance",
      icon: Wallet,
    },
    {
      type: "link",
      id: "fee-settings",
      label: t("navigation.feeSettings"),
      href: "/fee-settings",
      icon: Receipt,
    },
    ...(canAccessDistributor ? [divider, distributorNavItem] : []),
  ]);

  function buildNavItems(
    isAmbassadorDistributor: boolean,
    isDistributorAccount: boolean,
    canAccessDistributor: boolean,
    graduated: boolean,
    isApiLogin: boolean
  ): NavItem[] {
    if (isAmbassadorDistributor) {
      return AMBASSADOR_NAV_ITEMS;
    }

    if (isApiLogin) {
      if (isDistributorAccount) {
        return withOrderlyEcosystemAndSettings(
          canAccessDistributor ? [distributorNavItem] : []
        );
      }

      return withOrderlyEcosystemAndSettings([
        {
          type: "link",
          id: "finance",
          label: t("navigation.finance"),
          href: "/finance",
          icon: Wallet,
        },
        { type: "divider" },
        { type: "header", label: t("navigation.dexConfigurations") },
        {
          type: "link",
          id: "fee-settings",
          label: t("navigation.feeSettings"),
          href: "/fee-settings",
          icon: Receipt,
        },
        {
          type: "link",
          id: "order-tags",
          label: t("navigation.orderEnum"),
          href: "/order-tags",
          icon: Tag,
        },
        { type: "divider" },
        { type: "header", label: t("navigation.growth") },
        {
          type: "link",
          id: "affiliate",
          label: t("navigation.affiliateProgram"),
          href: "/affiliate",
          icon: Users,
        },
        {
          type: "link",
          id: "points",
          label: t("navigation.pointsSystem"),
          href: "/points",
          icon: PointsIcon,
        },
        ...(canAccessDistributor ? [distributorNavItem] : []),
        { type: "divider" },
        { type: "header", label: t("navigation.dataAnalytics") },
        {
          type: "link",
          id: "data-analytics",
          label: t("navigation.users"),
          href: "/data-analytics/users",
          icon: BarChart3,
        },
        {
          type: "link",
          id: "data-analytics-platform",
          label: t("navigation.platform"),
          href: "/data-analytics/platform",
          icon: Database,
        },
        { type: "divider" },
        { type: "header", label: t("navigation.listing") },
        {
          type: "link",
          id: "permissionless-listing",
          label: t("navigation.permissionlessListing"),
          href: "/permissionless-listing",
          icon: List,
        },
      ]);
    }

    if (isDistributorAccount) {
      return DISTRIBUTOR_NAV_ITEMS;
    }

    if (graduated) {
      return ALL_NAV_ITEMS;
    }

    const allowedItems: NavItem[] = [
      {
        type: "link",
        id: "dashboard",
        label: t("navigation.myDex"),
        href: "/home",
        icon: LayoutGrid,
      },
    ];

    allowedItems.push({ type: "divider" });
    allowedItems.push({
      type: "header",
      label: t("navigation.dexConfigurations"),
    });
    allowedItems.push({
      type: "link",
      id: "frontend-setup",
      label: t("navigation.frontendSetup"),
      href: "/frontend-setup",
      icon: Settings2,
    });

    return withOrderlyEcosystemAndSettings(allowedItems);
  }

  const navItems = buildNavItems(
    isAmbassadorDistributor,
    isDistributorAccount,
    canAccessDistributor,
    graduated,
    isApiLogin
  );

  function renderSidebarContent(
    isCollapsed: boolean,
    showCollapseToggle: boolean
  ) {
    const header = (
      <LocalizedLink
        to="/"
        className={`flex items-center gap-3 border-b border-[var(--border-subtle)] px-6 py-5 ${
          isCollapsed ? "justify-center px-4" : ""
        }`}
        aria-label="Orderly One home"
        onClick={() => closeMobile()}
      >
        <SidebarBrand collapsed={isCollapsed} />
      </LocalizedLink>
    );

    const nav = (
      <nav
        className={`flex-1 overflow-y-auto py-3 scrollbar-hide ${isCollapsed ? "px-2.5" : "px-4"}`}
      >
        <ul className="flex flex-col gap-1">
          {navItems.map((item, idx) => {
            if (item.type === "divider") {
              return (
                <li
                  key={`divider-${idx}`}
                  className={`my-1 h-px bg-[var(--border-subtle)] ${isCollapsed ? "mx-2" : ""}`}
                />
              );
            }
            if (item.type === "header") {
              if (isCollapsed) return null;
              return (
                <li
                  key={`header-${idx}`}
                  className="px-3.5 pt-3 pb-1 text-[10px] font-semibold uppercase tracking-wider text-fg-secondary/70"
                >
                  {item.label}
                </li>
              );
            }
            const active = isItemActive(pathname, item);
            const Icon = item.icon;
            const content = (
              <>
                <Icon
                  className={`h-[18px] w-[18px] shrink-0 transition-colors ${active ? "text-[var(--fg-base)]" : "text-[var(--fg-secondary)] group-hover:text-[var(--fg-base)]"}`}
                />
                {!isCollapsed && (
                  <span className="flex flex-1 items-center gap-1.5">
                    <span
                      className={`truncate transition-colors ${active ? "text-[var(--fg-base)]" : "text-[var(--fg-secondary)] group-hover:text-[var(--fg-base)]"}`}
                    >
                      {item.label}
                    </span>
                    {item.external && (
                      <svg
                        width="12"
                        height="12"
                        viewBox="0 0 24 24"
                        fill="none"
                        stroke="currentColor"
                        strokeWidth="2"
                        strokeLinecap="round"
                        strokeLinejoin="round"
                        className="shrink-0 text-[var(--fg-secondary)] transition-colors group-hover:text-[var(--fg-base)]"
                      >
                        <path d="M18 13v6a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h6" />
                        <polyline points="15 3 21 3 21 9" />
                        <line x1="10" y1="14" x2="21" y2="3" />
                      </svg>
                    )}
                  </span>
                )}
              </>
            );
            const className = `group flex items-center gap-3 rounded-xl border px-3.5 py-2.5 text-sm font-medium transition-colors ${
              active
                ? "border-[var(--border-primary)] bg-[var(--bg-primary-subtle)] text-[var(--fg-base)]"
                : "border-transparent text-[var(--fg-secondary)] hover:bg-[var(--bg-hover)] hover:text-[var(--fg-base)]"
            } ${isCollapsed ? "justify-center px-2.5" : ""}`;

            return (
              <li key={item.id}>
                {item.external ? (
                  <a
                    href={item.href}
                    target="_blank"
                    rel="noopener noreferrer"
                    className={className}
                  >
                    {content}
                  </a>
                ) : (
                  <LocalizedLink to={item.href} className={className}>
                    {content}
                  </LocalizedLink>
                )}
              </li>
            );
          })}
        </ul>
      </nav>
    );

    const footer = (
      <div
        className={`border-t border-[var(--border-subtle)] py-3 ${
          isCollapsed ? "px-2.5" : "px-4"
        }`}
      >
        <div
          className={`flex items-center ${isCollapsed ? "justify-center" : "justify-between"}`}
        >
          {!isCollapsed && <LanguageSwitcher dropUp align="left" />}
          {!showCollapseToggle && <NetworkSelector dropUp />}
          {showCollapseToggle && (
            <button
              type="button"
              onClick={toggleSidebar}
              aria-label={
                isCollapsed ? t("common.expand") : t("common.collapse")
              }
              className={`flex h-7 w-7 items-center justify-center rounded-lg text-fg-secondary transition-colors hover:bg-bg-hover hover:text-[var(--fg-base)] ${
                isCollapsed ? "mx-auto rotate-180" : ""
              }`}
            >
              <PanelLeft className="h-4 w-4" />
            </button>
          )}
        </div>
      </div>
    );

    return { header, nav, footer };
  }

  const desktopContent = renderSidebarContent(collapsed, true);
  const mobileContent = renderSidebarContent(false, false);

  if (!mounted) {
    return (
      <aside
        className="hidden md:flex fixed bottom-0 left-0 top-0 z-50 w-[240px] flex-col border-r border-[var(--border-subtle)] bg-bg-surface-primary"
        aria-label={t("common.sidebar")}
      >
        <div className="flex items-center border-b border-[var(--border-subtle)] px-6 py-5">
          <SidebarBrand collapsed={false} />
        </div>
        <nav className="flex-1 overflow-y-auto py-3 px-4 scrollbar-hide" />
      </aside>
    );
  }

  return (
    <>
      <aside
        className={`hidden md:flex fixed bottom-0 left-0 top-0 z-50 flex-col border-r border-[var(--border-subtle)] bg-bg-surface-primary ${
          collapsed ? "w-[72px]" : "w-[240px]"
        }`}
        aria-label={t("common.sidebar")}
      >
        {desktopContent.header}
        {desktopContent.nav}
        {desktopContent.footer}
      </aside>

      {mobileOpen && (
        <div
          className="fixed inset-0 z-50 bg-bg-overlay md:hidden"
          onClick={() => closeMobile()}
        />
      )}
      <aside
        className={`fixed bottom-0 left-0 top-0 z-50 flex flex-col border-r border-line-subtle bg-bg-surface-primary w-[280px] transition-transform duration-300 ease-in-out md:hidden ${
          mobileOpen ? "translate-x-0" : "-translate-x-full"
        }`}
        aria-label={t("common.sidebar")}
        aria-hidden={!mobileOpen}
      >
        {mobileContent.header}
        {mobileContent.nav}
        {mobileContent.footer}
      </aside>
    </>
  );
}

function SidebarBrand({ collapsed }: { collapsed: boolean }) {
  return collapsed ? (
    <div className="h-8 w-8 shrink-0">
      <OrderlyLogo className="h-full w-full" />
    </div>
  ) : (
    <OrderlyOneMobileLogoLockup className="h-[26px] w-[149px] shrink-0" />
  );
}

function getRoutePathname(pathname: string) {
  const segments = pathname.split("/").filter(Boolean);
  if (segments.length > 0 && /^[a-z]{2}$/i.test(segments[0])) {
    return segments.length === 1 ? "/" : `/${segments.slice(1).join("/")}`;
  }
  return pathname;
}

function isItemActive(
  pathname: string,
  item: { id: string; href: string; external?: boolean }
): boolean {
  if (item.id === "dashboard") return pathname === "/home";
  if (item.external) return false;
  if (item.id === "frontend-setup")
    return (
      pathname === "/frontend-setup" ||
      pathname === "/deployment-status" ||
      pathname === "/dex-config" ||
      pathname === "/custom-domain"
    );
  if (item.id === "data-analytics")
    return (
      pathname === "/data-analytics" ||
      pathname === "/data-analytics/users" ||
      pathname.startsWith("/data-analytics/users/")
    );
  return pathname === item.href;
}
