import { useEffect, useState } from "react";
import { ArrowRight, KeyRound } from "lucide-react";
import {
  hasCompleteStoredAdminApiKey,
  shouldRequireOrderlyApiKey,
} from "@/utils/adminKeyAuth";
import { type Profile, getProfile } from "@/utils/branding-shared";
import { CreateOrderlyKeyModal } from "@/components/orderly/CreateOrderlyKeyModal";

export function CreateApiKeyNotice({ className = "" }: { className?: string }) {
  const [modalOpen, setModalOpen] = useState(false);
  const [profile, setProfile] = useState<Profile | null>(() => getProfile());
  const [hasKey, setHasKey] = useState(() =>
    typeof window !== "undefined" ? hasCompleteStoredAdminApiKey() : false
  );

  const needsKey =
    !hasKey && profile ? shouldRequireOrderlyApiKey(profile) : false;
  const [visible, setVisible] = useState(needsKey);

  useEffect(() => {
    function sync() {
      setProfile(getProfile());
      setHasKey(hasCompleteStoredAdminApiKey());
    }
    window.addEventListener("authChanged", sync);
    window.addEventListener("profileUpdated", sync);
    window.addEventListener("storage", sync);
    return () => {
      window.removeEventListener("authChanged", sync);
      window.removeEventListener("profileUpdated", sync);
      window.removeEventListener("storage", sync);
    };
  }, []);

  useEffect(() => {
    if (!needsKey) {
      setVisible(false);
      return;
    }
    if (visible) return;

    const id = requestAnimationFrame(() => setVisible(true));
    return () => cancelAnimationFrame(id);
  }, [needsKey, visible]);

  if (!needsKey && !visible) return null;

  return (
    <>
      <div
        className={`grid transition-[grid-template-rows,opacity,margin] duration-300 ease-in-out ${
          visible
            ? "grid-rows-[1fr] opacity-100 mt-0"
            : "grid-rows-[0fr] opacity-0 -mt-2"
        } ${className}`}
      >
        <div className="overflow-hidden">
          <section className="rounded-2xl border border-(--border-warning) bg-(--bg-warning-subtle) px-4 py-3">
            <div className="flex flex-col gap-3 lg:flex-row lg:items-center lg:justify-between">
              <div className="min-w-0">
                <div className="flex flex-wrap items-center gap-2 text-sm">
                  <KeyRound className="h-4 w-4 text-(--fg-warning)" />
                  <span className="font-medium text-(--fg-base)">
                    API key required
                  </span>
                </div>
                <p className="mt-1 text-xs text-(--fg-secondary)">
                  Create an Orderly key to access dashboard data and manage your
                  account.
                </p>
              </div>
              <button
                type="button"
                onClick={() => setModalOpen(true)}
                className="inline-flex shrink-0 items-center justify-center gap-2 rounded-full px-4 py-2 text-xs font-semibold text-(--fg-base) transition-opacity hover:opacity-90"
                style={{ background: "var(--bg-primary)" }}
              >
                Create API key
                <ArrowRight className="h-3.5 w-3.5" />
              </button>
            </div>
          </section>
        </div>
      </div>

      <CreateOrderlyKeyModal
        open={modalOpen}
        onClose={() => setModalOpen(false)}
        onSuccess={() => setModalOpen(false)}
        brokerId={profile?.brokerId || ""}
        delegateContract={
          profile?.adminType === "multisig"
            ? profile.multisigAddress
            : undefined
        }
      />
    </>
  );
}
