import { useState } from "react";
import { OdsSelector } from "./OdsSelector";
import { getOrderlyEnv, type OrderlyEnv } from "@/utils/environment";

const SUPPORTED_NETWORKS = [
  { id: "ethereum", name: "Ethereum", chainId: 1 },
  { id: "arbitrum", name: "Arbitrum", chainId: 42161 },
  { id: "base", name: "Base", chainId: 8453 },
];

const TESTNET_NETWORKS = [
  { id: "ethereum", name: "Sepolia", chainId: 11155111 },
  { id: "arbitrum", name: "Arbitrum Sepolia", chainId: 421614 },
  { id: "base", name: "Base Sepolia", chainId: 84532 },
];

function getNetworksForEnv(env: OrderlyEnv) {
  return env === "prod" ? SUPPORTED_NETWORKS : TESTNET_NETWORKS;
}

