export function NetworkSelector({
  className,
  dropUp,
}: {
  className?: string;
  dropUp?: boolean;
}) {
  const [selectedNetwork, setSelectedNetwork] = useState(
    () => getNetworksForEnv(getOrderlyEnv())[0]
  );
  const availableNetworks = getNetworksForEnv(getOrderlyEnv());

  return (
    <OdsSelector
      ariaLabel={`Selected network: ${selectedNetwork.name}`}
      display="icon-only"
      dropUp={dropUp}
      className={className}
      onValueChange={chainId => {
        const next = availableNetworks.find(
          network => String(network.chainId) === chainId
        );
        if (next) setSelectedNetwork(next);
      }}
      options={availableNetworks.map(network => ({
        value: String(network.chainId),
        label: network.name,
        icon: <NetworkLogo network={network.id} />,
      }))}
      size="large"
      title={selectedNetwork.name}
      value={String(selectedNetwork.chainId)}
    />
  );
}
