import React, { useEffect, useState } from "react";
import { LocalizedLink } from "@/utils/localizedRoute";
import { cn } from "@/lib/utils";
import { AppHeader } from "./AppHeader";
import { CreateApiKeyNotice } from "./CreateApiKeyNotice";
import {
  getInitialSidebarCollapsed,
  getStoredSidebarCollapsed,
  shouldCollapseSidebarForViewport,
  SIDEBAR_COLLAPSE_MEDIA_QUERY,
} from "@/utils/sidebar";

export type PageShellConfig = {
  pageTitle: string;
  parentTitle?: string;
  parentHref?: string;
  contentClassName?: string;
};

export type PageShellOutletContext = {
  setPageShellConfig: React.Dispatch<React.SetStateAction<PageShellConfig>>;
};

export const DEFAULT_PAGE_SHELL_CONFIG: PageShellConfig = {
  pageTitle: "Orderly One",
};

const PageShellContext = React.createContext<PageShellOutletContext | null>(
  null
);

export function PageShellProvider({
  children,
  value,
}: {
  children: React.ReactNode;
  value: PageShellOutletContext;
}) {
  return (
    <PageShellContext.Provider value={value}>
      {children}
    </PageShellContext.Provider>
  );
}

export function DashboardPageFrame({
  pageTitle,
  parentTitle,
  children,
}: Pick<PageShellConfig, "pageTitle" | "parentTitle"> & {
  children: React.ReactNode;
}) {
  const [sidebarCollapsed, setSidebarCollapsed] = useState(false);

  useEffect(() => {
    if (typeof window === "undefined") return;
    setSidebarCollapsed(getInitialSidebarCollapsed());
  }, []);

  useEffect(() => {
    if (typeof window === "undefined") return;

    function handleSidebarToggle(e: Event) {
      const custom = e as CustomEvent<{ collapsed: boolean }>;
      setSidebarCollapsed(custom.detail.collapsed);
    }

    function handleViewportChange() {
      if (getStoredSidebarCollapsed() !== null) return;
      setSidebarCollapsed(shouldCollapseSidebarForViewport());
    }

    const viewportQuery = window.matchMedia(SIDEBAR_COLLAPSE_MEDIA_QUERY);
    viewportQuery.addEventListener("change", handleViewportChange);
    window.addEventListener("sidebarToggle", handleSidebarToggle);
    return () => {
      viewportQuery.removeEventListener("change", handleViewportChange);
      window.removeEventListener("sidebarToggle", handleSidebarToggle);
    };
  }, []);

  const sidebarMargin = sidebarCollapsed
    ? "ml-0 md:ml-[72px]"
    : "ml-0 md:ml-[240px]";

  return (
    <div className="flex min-h-screen overflow-hidden bg-bg-base">
      <div
        className={`flex min-w-0 flex-1 flex-col transition-none md:transition-[margin] md:duration-200 ${sidebarMargin}`}
      >
        <AppHeader pageTitle={pageTitle} parentTitle={parentTitle} />
        <main className="flex-1 p-4 md:p-6">{children}</main>
      </div>
    </div>
  );
}

function PageShellContent({
  pageTitle,
  parentTitle,
  parentHref,
  contentClassName,
  children,
}: PageShellConfig & {
  children: React.ReactNode;
}) {
  return (
    <div className={cn("mx-auto w-full max-w-[960px]", contentClassName)}>
      <CreateApiKeyNotice className="mb-5" />
      {parentTitle && parentHref && (
        <div className="mb-6 flex items-center gap-2">
          <LocalizedLink
            to={parentHref}
            className="inline-flex items-center gap-1 rounded-lg px-2 py-1 text-sm text-fg-secondary transition-colors hover:bg-bg-hover hover:text-fg-base"
          >
            <svg
              width="14"
              height="14"
              viewBox="0 0 24 24"
              fill="none"
              stroke="currentColor"
              strokeWidth="2"
              strokeLinecap="round"
              strokeLinejoin="round"
            >
              <path d="m15 18-6-6 6-6" />
            </svg>
            {parentTitle}
          </LocalizedLink>
          <span className="text-fg-secondary">/</span>
          <span className="text-sm font-medium text-fg-base">{pageTitle}</span>
        </div>
      )}
      {children}
    </div>
  );
}

export function PageShell({
  pageTitle,
  parentTitle,
  parentHref,
  contentClassName,
  children,
}: PageShellConfig & {
  children: React.ReactNode;
}) {
  const pageShellContext = React.useContext(PageShellContext);
  const setPageShellConfig = pageShellContext?.setPageShellConfig;

  useEffect(() => {
    if (!setPageShellConfig) return;
    setPageShellConfig({
      pageTitle,
      parentTitle,
      parentHref,
    });
  }, [pageTitle, parentHref, parentTitle, setPageShellConfig]);

  if (!setPageShellConfig) {
    return (
      <DashboardPageFrame pageTitle={pageTitle} parentTitle={parentTitle}>
        <PageShellContent
          pageTitle={pageTitle}
          parentTitle={parentTitle}
          parentHref={parentHref}
          contentClassName={contentClassName}
        >
          {children}
        </PageShellContent>
      </DashboardPageFrame>
    );
  }

  return (
    <PageShellContent
      pageTitle={pageTitle}
      parentTitle={parentTitle}
      parentHref={parentHref}
      contentClassName={contentClassName}
    >
      {children}
    </PageShellContent>
  );
}
