export const SIDEBAR_COLLAPSED_STORAGE_KEY = "sidebarCollapsed";
export const SIDEBAR_COLLAPSE_MEDIA_QUERY = "(max-width: 1023px)";

export function getStoredSidebarCollapsed(): boolean | null {
  if (typeof window === "undefined") return null;
  const saved = window.localStorage.getItem(SIDEBAR_COLLAPSED_STORAGE_KEY);
  if (saved === "true") return true;
  if (saved === "false") return false;
  return null;
}

export function shouldCollapseSidebarForViewport() {
  return (
    typeof window !== "undefined" &&
    window.matchMedia(SIDEBAR_COLLAPSE_MEDIA_QUERY).matches
  );
}

export function getInitialSidebarCollapsed() {
  return getStoredSidebarCollapsed() ?? shouldCollapseSidebarForViewport();
}

export function saveSidebarCollapsed(collapsed: boolean) {
  if (typeof window === "undefined") return;
  window.localStorage.setItem(SIDEBAR_COLLAPSED_STORAGE_KEY, String(collapsed));
}
